# compute LCS length
def lcs_length(a, b):
    # dynamic programming for LCS (characters)
    m, n = len(a), len(b)
    # Use DP with O(m*n) memory maybe fine
    dp = [[0]*(n+1) for _ in range(m+1)]
    for i in range(m-1, -1, -1):
        for j in range(n-1, -1, -1):
            if a[i]==b[j]:
                dp[i][j] = dp[i+1][j+1] + 1
            else:
                dp[i][j] = max(dp[i+1][j], dp[i][j+1])
    return dp[0][0]

